<?php
namespace App\Models;use App\Models\Concerns\BelongsToWorkspace;use Illuminate\Database\Eloquent\Model;
class Invoice extends Model{use BelongsToWorkspace;protected $fillable=['workspace_id','subscription_id','invoice_number','status','currency','subtotal','discount_total','tax_total','total','amount_paid','amount_due','issue_date','due_date','paid_at','notes','metadata'];protected function casts():array{return ['issue_date'=>'date','due_date'=>'date','paid_at'=>'datetime','metadata'=>'array','subtotal'=>'decimal:2','total'=>'decimal:2','amount_paid'=>'decimal:2','amount_due'=>'decimal:2'];}public function workspace(){return $this->belongsTo(Workspace::class);}public function subscription(){return $this->belongsTo(Subscription::class);}public function items(){return $this->hasMany(InvoiceItem::class);}public function payments(){return $this->hasMany(Payment::class);}}
